const kv = await Deno.openKv();

interface User { id: string; name: string; email: string; }

async function getTyped<T>(key: Deno.KvKey): Promise<T | null> {
  const entry = await kv.get<T>(key);
  return entry.value; // T | null — no cast, no `as`
}

async function setTyped<T>(key: Deno.KvKey, value: T): Promise<void> {
  await kv.set(key, value);
}

await setTyped<User>(["users", "u1"], { id: "u1", name: "Ada", email: "ada@example.com" });
const user = await getTyped<User>(["users", "u1"]);
if (user) console.log(user.email); // fully typed, no assertion needed

type Result<T, E = Error> = { ok: true; value: T } | { ok: false; error: E };

async function readConfig(path: string): Promise<Result<string>> {
  try {
    const text = await Deno.readTextFile(path);
    return { ok: true, value: text };
  } catch (e) {
    if (e instanceof Deno.errors.NotFound) {
      return { ok: false, error: new Error(`Config not found: ${path}`) };
    }
    throw e; // re-throw unexpected errors (e.g. PermissionDenied)
  }
}

const result = await readConfig("./config.json");
if (!result.ok) { console.error(result.error.message); Deno.exit(1); }
console.log(result.value);

