// Size a Worker pool to physical cores for CPU-bound work
const cpus = navigator.hardwareConcurrency;

const pool = Array.from({ length: cpus }, () =>
  new Worker(new URL("./compute_worker.ts", import.meta.url), { type: "module" })
);

let cursor = 0;
function dispatch<T>(payload: unknown): Promise<T> {
  const worker = pool[cursor++ % cpus];
  return new Promise((resolve) => {
    worker.addEventListener("message", ({ data }) => resolve(data as T), { once: true });
    worker.postMessage(payload);
  });
}

// Deno.serve stays non-blocking; heavy work goes to the pool
Deno.serve({ port: 8000 }, async (req) => {
  const result = await dispatch<string>(await req.text());
  return new Response(result);
});

